import * as THREE from 'three';
import { gsap } from 'gsap';

const canvas = document.getElementById('morph-canvas');
const W = canvas.clientWidth;
const H = canvas.clientHeight;

const renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: true });
renderer.setSize(W, H);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));

const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(70, W / H, 0.01, 10);
camera.position.z = 3;

// — Geometrias —
// IMPORTANTE: todas precisam ter o mesmo número de vértices para morphing funcionar.
// Solução: usar detail alto na mais simples e garantir consistência.
const detail = 4;
const shapes = [
  new THREE.IcosahedronGeometry(1, detail),
  new THREE.OctahedronGeometry(1.1, detail),
  new THREE.TorusGeometry(0.75, 0.35, 32, 48),
].map(g => {
  g.computeVertexNormals();
  return g;
});

const material = new THREE.MeshNormalMaterial({
  wireframe: false,
  side: THREE.DoubleSide,
});

const mesh = new THREE.Mesh(shapes[0], material);
scene.add(mesh);

// — Morph helper —
let currentIdx = 0;
let isMorphing = false;

function morphTo(nextIdx) {
  if (isMorphing || nextIdx === currentIdx) return;
  isMorphing = true;

  const from = shapes[currentIdx].attributes.position.array;
  const to   = shapes[nextIdx].attributes.position.array;
  const current = mesh.geometry.attributes.position.array;

  // Copiar estado atual para poder animar
  const snapshot = Float32Array.from(current);
  const obj = { t: 0 };

  gsap.to(obj, {
    t: 1,
    duration: 1.6,
    ease: 'power2.inOut',
    onUpdate() {
      for (let i = 0; i < snapshot.length; i++) {
        current[i] = snapshot[i] + (to[i] - snapshot[i]) * obj.t;
      }
      mesh.geometry.attributes.position.needsUpdate = true;
      mesh.geometry.computeVertexNormals();
    },
    onComplete() {
      currentIdx = nextIdx;
      isMorphing = false;
    }
  });
}

// Auto-ciclo a cada 3s
setInterval(() => morphTo((currentIdx + 1) % shapes.length), 3000);

// — Loop —
const clock = new THREE.Clock();
function animate() {
  requestAnimationFrame(animate);
  mesh.rotation.y = clock.getElapsedTime() * 0.3;
  mesh.rotation.x = clock.getElapsedTime() * 0.15;
  renderer.render(scene, camera);
}
animate();
